(function(){
  function decodeCFEmail(encoded){
    try{
      var r='';
      var key = parseInt(encoded.substr(0,2),16);
      for(var i=2;i<encoded.length;i+=2){
        var ch = parseInt(encoded.substr(i,2),16) ^ key;
        r += String.fromCharCode(ch);
      }
      return r;
    }catch(e){return null;}
  }
  function run(){
    var els = document.querySelectorAll('.__cf_email__');
    els.forEach(function(el){
      var enc = el.getAttribute('data-cfemail');
      if(enc){
        var decoded = decodeCFEmail(enc);
        if(decoded){ el.textContent = decoded; }
      }
    });
  }
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded', run); else run();
})();
